import{_ as l,r as d,o as c,c as o,b as e,e as s,w as i,d as a,f as t}from"./app-55c326ac.js";const r={},u=e("h1",{id:"_03-使用docker镜像",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_03-使用docker镜像","aria-hidden":"true"},"#"),a(" 03. 使用Docker镜像")],-1),p={class:"table-of-contents"},b=t(`<p><strong>前言：</strong> Docker运行容器前需要本地存在对应的镜像，当本地不存在该镜像，Docker会从镜像仓库下载该镜像。</p><ul><li>从仓库获取镜像</li><li>管理本地主机上的镜像</li><li>镜像实现的基本原理</li></ul><h2 id="获取镜像" tabindex="-1"><a class="header-anchor" href="#获取镜像" aria-hidden="true">#</a> 获取镜像</h2><p>Docker Hub上存在大量的镜像，如何获取？<br> 获取Docker镜像仓库中的镜像命令： <code>docker pull</code>。格式：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>docker pull [选项] [docker Registry 地址[:端口号]/]仓库名[:标签]
 Docker镜像仓库地址：地址的格式一般为&lt;域名/IP&gt;[:端口号]。默认地址是 Docker Hub
 仓库名：仓库名是两段式名称，即&lt;用户名&gt;/&lt;软件名&gt;，如果不给出用户名。则默认为library，也就是官方镜像
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> pull ubuntu:18.04
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="运行镜像" tabindex="-1"><a class="header-anchor" href="#运行镜像" aria-hidden="true">#</a> 运行镜像</h3><p>当存在镜像后，就能够以这个镜像为基础启动并运行一个容器。 当打算启动镜像里面的bash并且进行交互式操作的话，可以执行下面的命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-it</span> <span class="token parameter variable">--rm</span> ubuntu:18.04 <span class="token function">bash</span>
<span class="token function">cat</span> /etc/os-release 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>NAME=&quot;Ubuntu&quot;
VERSION=&quot;18.04.1 LTS (Bionic Beaver)&quot;
ID=ubuntu
ID_LIKE=debian
PRETTY_NAME=&quot;Ubuntu 18.04.1 LTS&quot;
VERSION_ID=&quot;18.04&quot;
HOME_URL=&quot;https://www.ubuntu.com/&quot;
SUPPORT_URL=&quot;https://help.ubuntu.com/&quot;
BUG_REPORT_URL=&quot;https://bugs.launchpad.net/ubuntu/&quot;
PRIVACY_POLICY_URL=&quot;https://www.ubuntu.com/legal/terms-and-policies/privacy-policy&quot;
VERSION_CODENAME=bionic
UBUNTU_CODENAME=bionic
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># docker run    运行容器的命令
# -it     两个参数 -i：交互操作  -t 终端。因为进入bash执行一些命令并查看返回结果，需要交互式终端。
# --rm    表示的是：容器退出后随之将其删除。默认情况下，为了保障需求，退出的容器并不会立即删除，除非手动 docker rm。
# cat /etc/os-release  是我进入容器后，查看当前版本信息
# exit  表示的是退出容器
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="管理本地主机上的镜像" tabindex="-1"><a class="header-anchor" href="#管理本地主机上的镜像" aria-hidden="true">#</a> 管理本地主机上的镜像</h2><h3 id="列出镜像" tabindex="-1"><a class="header-anchor" href="#列出镜像" aria-hidden="true">#</a> 列出镜像</h3><p>要想列出已经下载下来的镜像，可以使用<code>docker images ls</code>命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> images <span class="token function">ls</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>列表包含了：<code>仓库名</code>、<code>标签</code>、<code>镜像ID</code>、<code>创建时间</code>以及<code>所占用的空间</code><br><code>镜像ID</code>则是镜像的唯一标识，一个镜像可以对应多个<code>标签</code>。当镜像ID相同，则表示是同一个镜像</p><h3 id="镜像体积" tabindex="-1"><a class="header-anchor" href="#镜像体积" aria-hidden="true">#</a> 镜像体积</h3><p>如果仔细观察，会注意到，这里标识的所占用空间和在 Docker Hub 上看到的镜像大小不同。 Docker Hub中显示的体积是压缩后的体积。在镜像下载和上传过程中镜像是保持压缩状态的，因此Docker Hub所显示的大小是网络传输中更关心的流量大小。</p><p>而<code>docker image ls</code>显示的是镜像下载到本地后，展开的大小，准确说，是展开后的各层所占用空间的总和，因为镜像到本地后，查看空间的时候，更关心的是本地磁盘空间占用的大小。</p><p>另外一个需要注意的问题是，<code>docker image ls</code> 列表中的镜像体积总和并非是所有镜像实际硬盘消耗。由于 Docker 镜像是<code>多层存储结构</code>，并且可以继承、复用，因此不同镜像可能会因为使用相同的基础镜像，从而拥有共同的层。由于 Docker 使用<code>Union FS</code>，相同的层只需要保存一份即可，因此实际镜像硬盘占用空间很可能要比这个列表镜像大小的总和要小的多<br> 可以通过下面的命令查看镜像 容器 数据卷所占用的空间</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> system <span class="token function">df</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="虚悬镜像" tabindex="-1"><a class="header-anchor" href="#虚悬镜像" aria-hidden="true">#</a> 虚悬镜像</h3><p>但给一个镜像没有仓库名，也没有标签，均为<code>&lt;none&gt;</code>.导致这种的情况的原因：<br> 由于进行维护，发布新的版本，当<code>docker pull</code>是就会出现这种情况。<code>docker build</code>也同样可以导致这种现象。<br> 由于新旧镜像同名，旧镜像名称被取消，从而出现仓库名、标签均为<code>&lt;none&gt;</code>的镜像。这类无标签镜像也成为虚悬镜像.<br> 可用下面的命令显示这类镜像</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">-f</span> <span class="token assign-left variable">dangling</span><span class="token operator">=</span>true

<span class="token comment"># 一般，虚悬镜像都是去了存在的价值，可以所以删除</span>
<span class="token function">docker</span> image prune  <span class="token comment">#删除虚悬镜像</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="中间层镜像" tabindex="-1"><a class="header-anchor" href="#中间层镜像" aria-hidden="true">#</a> 中间层镜像</h3><p>为了加速镜像构建、重复利用资源，Docker会利用中间层镜像。so：在使用一段时间后，可能会看到一些依赖的中间层镜像。默认的<code>docker image ls</code>列表只会显示顶层镜像。需要查看中间层镜像 用</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">-a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样会看到很多无标签的镜像，与之前的虚悬镜像不同，这些无标签的镜像很多都是中间层镜像，是其它镜像所依赖的镜像。这些无标签镜像不应该删除，否则会导致上层镜像因为依赖丢失而出错。实际上，这些镜像也没必要删除，因为之前说过，相同的层只会存一遍，而这些镜像是别的镜像的依赖，因此并不会因为它们被列出来而多存了一份，无论如何你也会需要它们。只要删除那些依赖它们的镜像后，这些依赖的中间层镜像也会被连带删除</p><h3 id="列出部分镜像" tabindex="-1"><a class="header-anchor" href="#列出部分镜像" aria-hidden="true">#</a> 列出部分镜像</h3><p>不加任何参数的情况下，docker image ls会列出所有顶级镜像，但只希望列出部分镜像。 <code>docker image ls</code> 有好几个参数可以选择<br> 1.根据仓库名列出镜像</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> image <span class="token function">ls</span> ubuntu
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>2.列出特定的某个镜像，</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> iamge <span class="token function">ls</span> ubuntu:18.04
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>除此，docker image ls 还支持强大的过滤参数 --filter 或者简写 -f</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 比如希望看到在mongo:3.2之后建立的镜像</span>
<span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">-f</span> <span class="token assign-left variable">since</span><span class="token operator">=</span>mongo:3.2

<span class="token comment"># 看某个位置之前的镜像 把since换成before</span>

<span class="token comment"># 当镜像构建时，定义了LABEL，还可以通过LABEL来过滤</span>
<span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">-f</span> <span class="token assign-left variable">label</span><span class="token operator">=</span>com.example.version<span class="token operator">=</span><span class="token number">0.1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="以特定格式显示" tabindex="-1"><a class="header-anchor" href="#以特定格式显示" aria-hidden="true">#</a> 以特定格式显示</h3><p><code>docker image ls</code> #输出一个完整的表格<br><code>docker image ls -q</code> 把所有镜像ID输出出来<br><code>--filter</code>配合<code>-q</code>产生出指定范围ID列表，然后送给另一个docker命令作为参数，从而针对这组实体成批的进行某种操作。<br> 当只是对表格的结构不满意，希望自己组织列；或者不希望有标题，这样方便其他程序解析结果等，就用到Go的模块语法</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 直接输出只包含镜像ID和仓库名：</span>
<span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">--format</span> <span class="token string">&quot;{{:ID}}:{{:Repository}}&quot;</span>

<span class="token comment"># 以表格等距显示，并有标题行，自己定义列</span>
<span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">--format</span> <span class="token string">&quot;table{{.ID}}<span class="token entity" title="\\t">\\t</span>{{.Repository}}<span class="token entity" title="\\t">\\t</span>{{.Tag}}&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="删除本地镜像" tabindex="-1"><a class="header-anchor" href="#删除本地镜像" aria-hidden="true">#</a> 删除本地镜像</h2><ul><li>用ID、镜像名、摘要删除镜像</li><li>Untagged和Deleted</li><li>用docker image ls进行配合</li><li>Centos/RHEL需要注意的问题</li></ul><p>删除镜像的格式：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> image <span class="token function">rm</span> <span class="token punctuation">[</span>选项<span class="token punctuation">]</span> <span class="token operator">&lt;</span>镜像<span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token operator">&lt;</span>镜像<span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span> <span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="用id、镜像名、摘要删除镜像" tabindex="-1"><a class="header-anchor" href="#用id、镜像名、摘要删除镜像" aria-hidden="true">#</a> 用ID、镜像名、摘要删除镜像</h3><p>&lt;镜像&gt;可以是<code>镜像短ID</code>、<code>镜像长ID</code>、 <code>镜像名</code> 或者<code>镜像摘要</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> image <span class="token function">ls</span>
<span class="token function">docker</span> iamge <span class="token function">rm</span> 镜像ID
<span class="token function">docker</span> image <span class="token function">rm</span> 镜像名
<span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">--digests</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>REPOSITORY                  TAG                 DIGEST                                                                    IMAGE ID            CREATED             SIZE
node                        slim                sha256:b4f0e0bdeb578043c1ea6862f0d40cc4afe32a4a582f3be235a3b164422be228   6e0c4c8e3913        3 weeks ago         214 MB
docker image rm node@sha256:b4f0e0bdeb578043c1ea6862f0d40cc4afe32a4a582f3be235a3b164422be228
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="untagged和deleted" tabindex="-1"><a class="header-anchor" href="#untagged和deleted" aria-hidden="true">#</a> Untagged和Deleted</h3><p>镜像的删除行为分为两类：</p><ul><li><code>Untagged</code></li><li><code>Deleted</code><br> 镜像的唯一标识是<code>其ID</code>和<code>摘要</code>，而一个镜像可以有多个标签<br> 因此当我们使用上面命令删除镜像的时候，实际上是在要求删除某个标签的镜像。<br> 所以首先需要做的是将满足我们要求的所有镜像标签都取消，这就是我们看到的 <code>Untagged</code> 的信息。<br> 因为一个镜像可以对应多个标签，因此当我们删除了所指定的标签后，可能还有别的标签指向了这个镜像，如果是这种情况，那么 Delete 行为就不会发生。<br> 所以并非所有的 <code>docker image rm</code> 都会产生删除镜像的行为，有可能仅仅是取消了某个标签而已.<br> 当该镜像所有的标签都被取消了，该镜像很可能会失去了存在的意义，因此会触发删除行为 。镜像是多层存储结构，因此在删除的时候也是从上层向基础层方向依次进行判断删除。镜像的多层结构让镜像复用变动非常容易，因此很有可能某个其它镜像正依赖于当前镜像的某一层。这种情况，依旧不会触发删除该层的行为。直到没有任何层依赖当前层时，才会真实的删除当前层。这就是为什么，有时候会奇怪，为什么明明没有别的标签指向这个镜像，但是它还是存在的原因，也是为什么有时候会发现所删除的层数和自己 <code>docker pull</code> 看到的层数不一样的源。</li></ul><p>除了镜像依赖以外，还需要注意的是容器对镜像的依赖。如果有用这个镜像启动的容器存在（即使容器没有运行），那么同样不可以删除这个镜像。之前讲过，容器是以镜像为基础，再加一层容器存储层，组成这样的多层存储结构去运行的。因此该镜像如果被这个容器所依赖的，那么删除必然会导致故障。如果这些容器是不需要的，应该先将它们删除，然后再来删除镜像。</p><h3 id="用docker-image-ls命令进行配合" tabindex="-1"><a class="header-anchor" href="#用docker-image-ls命令进行配合" aria-hidden="true">#</a> 用docker image ls命令进行配合</h3><p>像其他可以承接多个实体的命令一样，可以使用 <code>docker image ls -q</code>来配合使用 <code>docker image rm</code>，这样可以成批的删除希望删除的镜像。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 如：我们需要删除所有仓库名为redis的镜像：  </span>
<span class="token function">docker</span> image <span class="token function">rm</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">docker</span> images <span class="token function">ls</span> <span class="token parameter variable">-q</span> redis<span class="token variable">)</span></span>
<span class="token comment"># 或者删除所有在mongo:3.2之前的镜像</span>
<span class="token function">docker</span> image <span class="token function">rm</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">docker</span> image <span class="token function">ls</span> <span class="token parameter variable">-q</span> <span class="token parameter variable">-f</span> <span class="token assign-left variable">before</span><span class="token operator">=</span>mongo:3.2<span class="token variable">)</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,54);function m(v,k){const n=d("router-link");return c(),o("div",null,[u,e("nav",p,[e("ul",null,[e("li",null,[s(n,{to:"#获取镜像"},{default:i(()=>[a("获取镜像")]),_:1}),e("ul",null,[e("li",null,[s(n,{to:"#运行镜像"},{default:i(()=>[a("运行镜像")]),_:1})])])]),e("li",null,[s(n,{to:"#管理本地主机上的镜像"},{default:i(()=>[a("管理本地主机上的镜像")]),_:1}),e("ul",null,[e("li",null,[s(n,{to:"#列出镜像"},{default:i(()=>[a("列出镜像")]),_:1})]),e("li",null,[s(n,{to:"#镜像体积"},{default:i(()=>[a("镜像体积")]),_:1})]),e("li",null,[s(n,{to:"#虚悬镜像"},{default:i(()=>[a("虚悬镜像")]),_:1})]),e("li",null,[s(n,{to:"#中间层镜像"},{default:i(()=>[a("中间层镜像")]),_:1})]),e("li",null,[s(n,{to:"#列出部分镜像"},{default:i(()=>[a("列出部分镜像")]),_:1})]),e("li",null,[s(n,{to:"#以特定格式显示"},{default:i(()=>[a("以特定格式显示")]),_:1})])])]),e("li",null,[s(n,{to:"#删除本地镜像"},{default:i(()=>[a("删除本地镜像")]),_:1}),e("ul",null,[e("li",null,[s(n,{to:"#用id、镜像名、摘要删除镜像"},{default:i(()=>[a("用ID、镜像名、摘要删除镜像")]),_:1})]),e("li",null,[s(n,{to:"#untagged和deleted"},{default:i(()=>[a("Untagged和Deleted")]),_:1})]),e("li",null,[s(n,{to:"#用docker-image-ls命令进行配合"},{default:i(()=>[a("用docker image ls命令进行配合")]),_:1})])])])])]),b])}const g=l(r,[["render",m],["__file","Docker系列学习-03.使用Docker镜像.html.vue"]]);export{g as default};
